import argparse
from kafka import KafkaAdminClient
from kafka.admin import NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import TopicAlreadyExistsError, UnknownTopicOrPartitionError
import sys

def create_topics(admin_client, topics_config):
    topics = []
    for topic_config in topics_config:
        topic_name, partitions, replication_factor, configs = topic_config
        topic = NewTopic(
            name=topic_name,
            num_partitions=partitions,
            replication_factor=replication_factor,
            topic_configs=configs
        )
        topics.append(topic)
    
    try:
        created_topics = admin_client.create_topics(topics, validate_only=False)
        print("Topics created successfully:")
        for topic_name, error in created_topics.items():
            if error is None:
                print(f"  - {topic_name}")
            else:
                print(f"  - {topic_name}: {error}")
    except Exception as e:
        print(f"Error creating topics: {e}")

def list_topics(admin_client):
    try:
        topics = admin_client.list_topics()
        print("Existing topics:")
        for topic in sorted(topics):
            print(f"  - {topic}")
    except Exception as e:
        print(f"Error listing topics: {e}")

def describe_topic(admin_client, topic_name):
    try:
        topic_configs = admin_client.describe_configs([
            ConfigResource(ConfigResourceType.TOPIC, topic_name)
        ])
        print(f"Configuration for topic '{topic_name}':")
        for resource, config in topic_configs.items():
            print(f"  {resource.name}:")
            for key, value in config.items():
                print(f"    {key}: {value}")
    except UnknownTopicOrPartitionError:
        print(f"Topic '{topic_name}' does not exist")
    except Exception as e:
        print(f"Error describing topic: {e}")

def delete_topic(admin_client, topic_name):
    try:
        admin_client.delete_topics([topic_name])
        print(f"Topic '{topic_name}' deletion initiated")
    except Exception as e:
        print(f"Error deleting topic: {e}")

def add_partitions(admin_client, topic_name, new_partition_count):
    try:
        admin_client.create_partitions([(topic_name, new_partition_count)])
        print(f"Added {new_partition_count} partitions to topic '{topic_name}'")
    except Exception as e:
        print(f"Error adding partitions: {e}")

def main():
    parser = argparse.ArgumentParser(description="Kafka Cluster Administration")
    parser.add_argument("--bootstrap-servers", default="localhost:9092", help="Bootstrap servers")
    parser.add_argument("--action", choices=["create", "list", "describe", "delete", "add-partitions"], required=True, help="Action to perform")
    parser.add_argument("--topic", help="Topic name for describe, delete, and add-partitions actions")
    parser.add_argument("--partitions", type=int, help="Number of partitions for create and add-partitions actions")
    parser.add_argument("--replication-factor", type=int, default=1, help="Replication factor for topic creation")
    parser.add_argument("--config", nargs="*", help="Topic configuration in key=value format")
    parser.add_argument("--topic-config", nargs="*", help="Topic names and their configurations for bulk creation")
    
    args = parser.parse_args()
    
    admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_servers)
    
    if args.action == "create":
        if not args.topic_config:
            print("Error: --topic-config is required for create action")
            sys.exit(1)
        
        topics_config = []
        for config_str in args.topic_config:
            parts = config_str.split(",")
            if len(parts) < 3:
                print(f"Invalid topic config format: {config_str}")
                sys.exit(1)
            
            topic_name = parts[0]
            partitions = int(parts[1])
            replication_factor = int(parts[2])
            configs = {}
            if len(parts) > 3:
                for config_pair in parts[3:]:
                    if "=" in config_pair:
                        key, value = config_pair.split("=", 1)
                        configs[key] = value
            
            topics_config.append((topic_name, partitions, replication_factor, configs))
        
        create_topics(admin_client, topics_config)
    
    elif args.action == "list":
        list_topics(admin_client)
    
    elif args.action == "describe":
        if not args.topic:
            print("Error: --topic is required for describe action")
            sys.exit(1)
        describe_topic(admin_client, args.topic)
    
    elif args.action == "delete":
        if not args.topic:
            print("Error: --topic is required for delete action")
            sys.exit(1)
        delete_topic(admin_client, args.topic)
    
    elif args.action == "add-partitions":
        if not args.topic or not args.partitions:
            print("Error: --topic and --partitions are required for add-partitions action")
            sys.exit(1)
        add_partitions(admin_client, args.topic, args.partitions)

if __name__ == "__main__":
    main()